# Worked focus: http-py-partial-and-ambiguous-outcomes — Represent partial results and unknown write outcomes so callers do not silently retry or declare success. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_responses_errors_3(status: int, problem_type: str | None) -> dict[str, object]:
    assert isinstance(status, int)
    if not 100 <= status <= 599:
        return {"kind": "invalid", "terminal": True}
    if 200 <= status < 300:
        return {"kind": "success", "terminal": status != 202}
    if 300 <= status < 400:
        return {"kind": "redirect", "terminal": False}
    return {"kind": "problem" if problem_type else "invalid", "terminal": True}

